@@ -85,8 +86,8 @@ class MemCpyOptPass : public PassInfoMixin<MemCpyOptPass> {
                                     Value *ByteVal);
   bool moveUp(StoreInst *SI, Instruction *P, const LoadInst *LI);
   bool performStackMoveOptzn(Instruction *Load, Instruction *Store,
